arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

// Train & save model at startup if not already present
if (!File.Exists(modelPath))
{
    TrainAndSaveModel(dataPath, modelPath);
}

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer JSON");

app.MapPost("/predict", (ChurnInput input, PredictionEnginePool<ChurnInput, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
        Score = prediction.Score,
    });
});

app.MapPost("/retrain", () =>
{
    TrainAndSaveModel(dataPath, modelPath);
    return Results.Ok("Model retrained successfully.");
});

app.Run();

static void TrainAndSaveModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    var data = mlContext.Data.LoadFromTextFile<ChurnInput>(
        dataPath, hasHeader: true, separatorChar: ',');

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

    var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(ChurnInput.Age),
            nameof(ChurnInput.Income),
            "RegionEncoded",
            nameof(ChurnInput.PurchaseHistory)))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
            labelColumnName: "Label", featureColumnName: "Features"));

    var model = pipeline.Fit(split.TrainSet);

    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

    Console.WriteLine("===== Churn Model Evaluation =====");
    Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
    Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
    Console.WriteLine($"F1 Score: {metrics.F1Score:F4}");
    Console.WriteLine("==================================");

    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");
}

